Response processNetworkRequests(const ReqStruct& request) {
    // Log the request
    std::cout << "Processing request #" << request.requestID 
              << " to endpoint: " << request.endpoint << std::endl;

    Response response;

    // Validate endpoint
    if (request.endpoint.empty() || request.endpoint[0] != '/') {
        response.statusCode = 400;
        response.message = "Invalid endpoint format";
        return response;
    }

    // Process different endpoints
    if (request.endpoint == "/api/data") {
        // Handle data endpoint
        if (request.payload.empty()) {
            response.statusCode = 400;
            response.message = "Empty payload";
        } else {
            response.statusCode = 200;
            response.message = "Success";
            response.data = "Processed: " + request.payload;
        }
    } else if (request.endpoint == "/api/status") {
        // Handle status endpoint
        response.statusCode = 200;
        response.message = "Server operational";
        response.data = "System running normally";
    } else {
        // Handle unknown endpoint
        response.statusCode = 404;
        response.message = "Endpoint not found";
    }

    // Log the response
    std::cout << "Response for request #" << request.requestID 
              << ": " << response.statusCode << " - " 
              << response.message << std::endl;

    return response;
}

