pub fn calculateStats(numbers: &[i32]) -> Option<(i32, i32, f64)> {
    if numbers.is_empty() {
        return None;
    }

    let mut min = numbers[0];
    let mut max = numbers[0];
    let mut sum = 0_i64;

    for &num in numbers {
        if num < min {
            min = num;
        }
        if num > max {
            max = num;
        }
        sum += num as i64;
    }

    let avg = sum as f64 / numbers.len() as f64;

    Some((min, max, avg))
}

