public List<Integer> analyzeNetworkConnectivity(Graph graph) {
    List<Integer> articulations = new ArrayList<>();
    boolean[] visited = new boolean[graph.V];
    int[] disc = new int[graph.V];
    int[] low = new int[graph.V];
    boolean[] isArticulation = new boolean[graph.V];
    int[] parent = new int[graph.V];

    Arrays.fill(parent, -1);

    int time = 0;

    for (int i = 0; i < graph.V; i++) {
        if (!visited[i]) {
            dfs(graph, i, visited, disc, low, parent, isArticulation, time);
        }
    }

    for (int i = 0; i < graph.V; i++) {
        if (isArticulation[i]) {
            articulations.add(i);
        }
    }

    return articulations;
}

private void dfs(Graph graph, int u, boolean[] visited, int[] disc, int[] low, 
                int[] parent, boolean[] isArticulation, int time) {

    int children = 0;
    visited[u] = true;
    disc[u] = low[u] = ++time;

    for (int v : graph.adjList[u]) {
        if (!visited[v]) {
            children++;
            parent[v] = u;

            dfs(graph, v, visited, disc, low, parent, isArticulation, time);

            low[u] = Math.min(low[u], low[v]);

            if (parent[u] == -1 && children > 1) {
                isArticulation[u] = true;
            }

            if (parent[u] != -1 && low[v] >= disc[u]) {
                isArticulation[u] = true;
            }
        } else if (v != parent[u]) {
            low[u] = Math.min(low[u], disc[v]);
        }
    }
}

