std::vector<std::string> splitString(const std::string& input, char delimiter) {
    std::vector<std::string> tokens;
    std::stringstream ss(input);
    std::string token;

    while (std::getline(ss, token, delimiter)) {
        tokens.push_back(token);
    }

    return tokens;
}

void processCommandLine(const std::string& commandStr, Configuration& config) {
    std::vector<std::string> args = splitString(commandStr, ' ');

    if (args.empty()) {
        return;
    }

    std::string command = args[0];

    if (command == "set" && args.size() >= 3) {
        config.set(args[1], args[2]);
    }
    else if (command == "display") {
        config.display();
    }
    else if (command == "reset") {
        config.reset();
    }
    else if (command == "get" && args.size() >= 2) {
        std::cout << args[1] << " = " << config.get(args[1]) << std::endl;
    }
    else {
        std::cout << "Unknown command or incorrect arguments: " << commandStr << std::endl;
    }
}

