struct AirportGates {
    gates: Vec<Gate>,
}

impl AirportGates {
    fn new() -> Self {
        AirportGates { gates: Vec::new() }
    }

    fn add_gate(&mut self, gate_id: String) {
        self.gates.push(Gate {
            id: gate_id,
            is_occupied: false,
            flight_number: None,
        });
    }
}

fn manageAirportGates(airport: &mut AirportGates, action: GateAction) -> Result<String, String> {
    match action.action_type {
        ActionType::Allocate => {
            for gate in &mut airport.gates {
                if gate.id == action.gate_id {
                    if gate.is_occupied {
                        return Err(format!("Gate {} is already occupied", action.gate_id));
                    }
                    gate.is_occupied = true;
                    gate.flight_number = action.flight_number.clone();
                    return Ok(format!("Gate {} allocated successfully to flight {:?}", 
                                     action.gate_id, action.flight_number));
                }
            }
            Err(format!("Gate {} not found", action.gate_id))
        },
        ActionType::Deallocate => {
            for gate in &mut airport.gates {
                if gate.id == action.gate_id {
                    if !gate.is_occupied {
                        return Err(format!("Gate {} is already free", action.gate_id));
                    }
                    gate.is_occupied = false;
                    let flight_number = gate.flight_number.clone();
                    gate.flight_number = None;
                    return Ok(format!("Gate {} deallocated successfully from flight {:?}", 
                                     action.gate_id, flight_number));
                }
            }
            Err(format!("Gate {} not found", action.gate_id))
        },
        ActionType::Status => {
            for gate in &airport.gates {
                if gate.id == action.gate_id {
                    let status = if gate.is_occupied {
                        format!("occupied by flight {:?}", gate.flight_number)
                    } else {
                        "free".to_string()
                    };
                    return Ok(format!("Gate {} is {}", action.gate_id, status));
                }
            }
            Err(format!("Gate {} not found", action.gate_id))
        }
    }
}

