def manage_job_applications(operations: tuple):
    job_applications = {}
    results = []

    for operation in operations:
        op_type = operation[0]

        if op_type == "add":
            applicant_name = operation[1]
            job_position = operation[2]

            if applicant_name not in job_applications:
                job_applications[applicant_name] = []

            job_applications[applicant_name].append(job_position)
            results.append(f"Added {applicant_name} for {job_position}")

        elif op_type == "update":
            applicant_name = operation[1]
            old_position = operation[2]
            new_position = operation[3]

            if applicant_name in job_applications and old_position in job_applications[applicant_name]:
                index = job_applications[applicant_name].index(old_position)
                job_applications[applicant_name][index] = new_position
                results.append(f"Updated {applicant_name}'s application from {old_position} to {new_position}")
            else:
                results.append(f"Could not update: {applicant_name} not found for {old_position}")

        elif op_type == "remove":
            applicant_name = operation[1]
            job_position = operation[2] if len(operation) > 2 else None

            if applicant_name in job_applications:
                if job_position is not None:
                    if job_position in job_applications[applicant_name]:
                        job_applications[applicant_name].remove(job_position)
                        results.append(f"Removed {applicant_name}'s application for {job_position}")
                    else:
                        results.append(f"Could not remove: {job_position} not found for {applicant_name}")
                else:
                    del job_applications[applicant_name]
                    results.append(f"Removed all applications for {applicant_name}")
            else:
                results.append(f"Could not remove: {applicant_name} not found")

    return (job_applications, results)

