        return resultGraph;
    }

    private void dfsRecursive(String node, Set<String> visited, Graph resultGraph, boolean isDirected) {
        visited.add(node);
        resultGraph.addNode(node);

        List<String> neighbors = graph.getNeighbors(node);
        for (String neighbor : neighbors) {
            if (!visited.contains(neighbor)) {
                resultGraph.addEdge(node, neighbor, isDirected);
                dfsRecursive(neighbor, visited, resultGraph, isDirected);
            }
        }
    }

    private Graph performDFS(String startNode, boolean isDirected) {
        Graph resultGraph = new Graph();
        if (startNode == null || startNode.isEmpty()) return resultGraph;

        Set<String> visited = new HashSet<>();
        dfsRecursive(startNode, visited, resultGraph, isDirected);

        return resultGraph;
    }
}
