        }
        "gif" => {
            img.write_to(&mut buffer, image::ImageOutputFormat::Gif)?;
        }
        "bmp" => {
            img.write_to(&mut buffer, image::ImageOutputFormat::Bmp)?;
        }
        _ => return Err("Unsupported image format".into()),
    }

    Ok(buffer)
}

