struct Contact {
    struct Action {
        enum Type {
            ADD,
            DELETE,
            UPDATE,
            FETCH
        } type;

        std::string searchCriteria;
    };

    struct Info {
        std::string name;
        std::string phone;
        std::string email;
        std::string address;
    };

    Action action;
    Info info;
};

bool manageContacts(std::vector<Contact::Info>& contactList, const Contact& request, std::vector<Contact::Info>& result) {
    result.clear();

    switch (request.action.type) {
        case Contact::Action::ADD: {
            contactList.push_back(request.info);
            return true;
        }

        case Contact::Action::DELETE: {
            auto it = std::remove_if(contactList.begin(), contactList.end(), 
                [&](const Contact::Info& contact) {
                    return contact.name == request.action.searchCriteria || 
                           contact.phone == request.action.searchCriteria ||
                           contact.email == request.action.searchCriteria;
                });

            bool found = it != contactList.end();
            contactList.erase(it, contactList.end());
            return found;
        }

        case Contact::Action::UPDATE: {
            for (auto& contact : contactList) {
                if (contact.name == request.action.searchCriteria || 
                    contact.phone == request.action.searchCriteria ||
                    contact.email == request.action.searchCriteria) {

                    if (!request.info.name.empty()) contact.name = request.info.name;
                    if (!request.info.phone.empty()) contact.phone = request.info.phone;
                    if (!request.info.email.empty()) contact.email = request.info.email;
                    if (!request.info.address.empty()) contact.address = request.info.address;

                    return true;
                }
            }
            return false;
        }

        case Contact::Action::FETCH: {
            for (const auto& contact : contactList) {
                if (request.action.searchCriteria.empty() ||
                    contact.name.find(request.action.searchCriteria) != std::string::npos ||
                    contact.phone.find(request.action.searchCriteria) != std::string::npos ||
                    contact.email.find(request.action.searchCriteria) != std::string::npos ||
                    contact.address.find(request.action.searchCriteria) != std::string::npos) {

                    result.push_back(contact);
                }
            }
            return !result.empty();
        }
    }

    return false;
}

pub fn calculateDivisors(n: i32) -> Vec<i32> {
    if n <= 0 {
        return Vec::new();
    }

    let mut divisors = Vec::new();
    let sqrt_n = (n as f64).sqrt() as i32;

    for i in 1..=sqrt_n {
        if n % i == 0 {
            divisors.push(i);
            if i != n / i {
                divisors.push(n / i);
            }
        }
    }

    divisors.sort();
    divisors
}

