class Phonebook {
private:
    std::vector<Contact> contacts;

public:
    bool addContact(const Contact& contact) {
        // Check if contact already exists
        auto it = std::find_if(contacts.begin(), contacts.end(), 
            [&contact](const Contact& c) { return c.name == contact.name; });

        if (it != contacts.end()) {
            return false; // Contact already exists
        }

        contacts.push_back(contact);
        return true;
    }

    bool deleteContact(const std::string& name) {
        auto it = std::find_if(contacts.begin(), contacts.end(),
            [&name](const Contact& c) { return c.name == name; });

        if (it == contacts.end()) {
            return false; // Contact not found
        }

        contacts.erase(it);
        return true;
    }

    bool updateContact(const std::string& name, const Contact& newDetails) {
        auto it = std::find_if(contacts.begin(), contacts.end(),
            [&name](const Contact& c) { return c.name == name; });

        if (it == contacts.end()) {
            return false; // Contact not found
        }

        *it = newDetails;
        return true;
    }

    std::vector<Contact> searchContact(const std::string& query) {
        std::vector<Contact> results;

        for (const auto& contact : contacts) {
            if (contact.name.find(query) != std::string::npos ||
                contact.phone.find(query) != std::string::npos ||
                contact.email.find(query) != std::string::npos ||
                contact.address.find(query) != std::string::npos) {
                results.push_back(contact);
            }
        }

        return results;
    }

    std::vector<Contact> getAllContacts() const {
        return contacts;
    }
};

